def search_products(
    keyword: Optional[str] = None,
    category: Optional[str] = None,
    manufacturer: Optional[str] = None,
    min_price: Optional[float] = None,
    max_price: Optional[float] = None,
    min_stock: Optional[int] = None,
    limit: int = 100,
    offset: int = 0
) -> TypingList[Dict]:
    
    builder = SearchQueryBuilder()
    
    if keyword:
        keyword_conditions = []
        for i, field in enumerate(['name', 'description', 'manufacturer'], start=builder.param_counter):
            keyword_conditions.append(f"{field} ILIKE ${i}")
            builder.params.append(f"%{keyword}%")
        builder.param_counter += 3
        builder.conditions.append(f"({' OR '.join(keyword_conditions)})")
    
